-- Ensure blog_posts has locale and brand columns (idempotent)
ALTER TABLE blog_posts
  ADD COLUMN IF NOT EXISTS locale TEXT NOT NULL DEFAULT 'en',
  ADD COLUMN IF NOT EXISTS brand  TEXT NOT NULL DEFAULT 'trainedby';

CREATE INDEX IF NOT EXISTS idx_blog_posts_locale ON blog_posts (locale);
CREATE INDEX IF NOT EXISTS idx_blog_posts_brand  ON blog_posts (brand);

INSERT INTO blog_posts (slug, title, meta_description, excerpt, content_markdown, keyword, tags, word_count, status, author, locale, brand, published_at)
